code = """import pandas as pd
import json

# Load books list from storage variable
books_children = var_call_h2cHuztl9TLKss9kIPelJaEG

# Load reviews JSON from file path stored in var_call_Aaisgi3j3yNtXB8TW8ikssii
reviews_path = var_call_Aaisgi3j3yNtXB8TW8ikssii
with open(reviews_path, 'r', encoding='utf-8') as f:
    reviews = json.load(f)

# Create DataFrame
df_reviews = pd.DataFrame(reviews)

# Ensure rating is numeric and review_time is datetime
if not df_reviews.empty:
    df_reviews['rating'] = pd.to_numeric(df_reviews['rating'], errors='coerce')
    df_reviews['review_time'] = pd.to_datetime(df_reviews['review_time'], errors='coerce')
else:
    df_reviews['rating'] = pd.Series(dtype=float)

# Aggregate by purchase_id
agg = df_reviews.groupby('purchase_id').agg(avg_rating=('rating', 'mean'), review_count=('rating', 'count')).reset_index()

# Map purchase_id to book_id by replacing prefix
agg['book_id'] = agg['purchase_id'].str.replace('purchaseid_', 'bookid_')

# Build lookup dict for avg and count
lookup = agg.set_index('book_id')[['avg_rating', 'review_count']].to_dict(orient='index')

# Check each children's book for avg >= 4.5
results = []
for b in books_children:
    bid = b.get('book_id')
    title = b.get('title')
    if bid in lookup:
        avg = lookup[bid]['avg_rating']
        cnt = int(lookup[bid]['review_count'])
        if avg is not None and avg >= 4.5 and cnt > 0:
            results.append({'book_id': bid, 'title': title, 'average_rating': round(float(avg),3), 'review_count': cnt})

# Sort results by average_rating desc then review_count desc
results = sorted(results, key=lambda x: (-x['average_rating'], -x['review_count'], x['title']))

print("__RESULT__:")
print(json.dumps(results))"""

